// ─── Padding (.origam--p-*) — 10 classes, 10 assertions ─────────────────────

test.describe('Utility classes — padding (.origam--p-*)', () => {
    for (const n of SPACES) {
        test(`origam--p-${n} — class present on swatch`, async ({ page }) => {
            const sb = await gotoVariant(page, VARIANTS.padding)
            const swatch = sb.locator(`[data-cy="util-p-${n}"]`)
            await expect(swatch).toBeVisible({ timeout: 5000 })

            // 1. Class is on the element
            await expect(swatch).toHaveClass(new RegExp(`origam--p-${n}(?![0-9])`))

            // 2. For non-zero steps, padding-top resolves to a non-zero px
            if (n !== '0') {
                const pt = await swatch.evaluate(el => getComputedStyle(el).paddingTop)
                expect(pt, `util-p-${n} computed padding-top`).not.toBe('')
                expect(pt, `util-p-${n} computed padding-top`).not.toBe('0px')
            }
        })
    }
})

