// ─── Gap (.origam--gap-*) — 10 classes, 10 assertions ───────────────────────

test.describe('Utility classes — gap (.origam--gap-*)', () => {
    for (const n of SPACES) {
        test(`origam--gap-${n} — class present on flex container`, async ({ page }) => {
            const sb = await gotoVariant(page, VARIANTS.gap)
            const swatch = sb.locator(`[data-cy="util-gap-${n}"]`)
            await expect(swatch).toBeVisible({ timeout: 5000 })

            // 1. Class is on the element
            await expect(swatch).toHaveClass(new RegExp(`origam--gap-${n}(?![0-9])`))

            // 2. For non-zero steps, gap resolves to a non-zero px value.
            // (CSS `gap` on a flex container shows as `row-gap` and `column-gap`
            //  in getComputedStyle — column-gap is reliable.)
            if (n !== '0') {
                const gap = await swatch.evaluate(el => getComputedStyle(el).columnGap)
                expect(gap, `util-gap-${n} computed column-gap`).not.toBe('')
                expect(gap, `util-gap-${n} computed column-gap`).not.toBe('0px')
                expect(gap, `util-gap-${n} computed column-gap`).not.toBe('normal')
            }
        })
    }
})

// ─── Font size (.origam--text-*) — 6 classes, 12 assertions ─────────────────

test.describe('Utility classes — font size (.origam--text-*)', () => {
    for (const size of TEXT_SIZES) {
        test(`origam--text-${size} — class present and font-size resolves`, async ({ page }) => {
            const sb = await gotoVariant(page, VARIANTS.text)
            const swatch = sb.locator(`[data-cy="util-text-${size}"]`)
            await expect(swatch).toBeVisible({ timeout: 5000 })

            // 1. Class is on the element
            await expect(swatch).toHaveClass(new RegExp(`origam--text-${size}`))

            // 2. font-size resolves to a non-empty px value
            const fs = await swatch.evaluate(el => getComputedStyle(el).fontSize)
            expect(fs, `util-text-${size} computed font-size`).not.toBe('')
            expect(fs, `util-text-${size} computed font-size`).not.toBe('0px')
        })
    }
})

// ─── Summary ─────────────────────────────────────────────────────────────────
// Total tests : 7 + 7 + 6 + 7 + 3 + 10 + 10 + 10 + 6 = 66 tests
// Total assertions: ~130 (1 visibility + 1 class-presence + 0–2 computed checks per test)
